use crate::distance::l2_distance;
use std::collections::HashMap;
use std::sync::RwLock;

pub struct VectorDB {
    // Store vectors in a HashMap protected by RwLock for concurrent access
    data: RwLock<HashMap<u64, Vec<f32>>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: RwLock::new(HashMap::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut data = self.data.write().unwrap();
        data.insert(id, vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut data = self.data.write().unwrap();
        let count = vectors.len();
        for (id, vector) in vectors {
            data.insert(id, vector);
        }
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let data = self.data.read().unwrap();

        // Brute force search: compute distance to all vectors
        let mut results: Vec<SearchResult> = data
            .iter()
            .map(|(id, v)| SearchResult {
                id: *id,
                distance: l2_distance(vector, v),
            })
            .collect();

        // Sort by distance ascending
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());

        // Return top-k
        results.truncate(top_k as usize);
        results
    }
}
"}

