use std::arch::x86_64::*;

#[cfg(target_arch = "x86_64")]
#[target_feature(enable = "avx512f")]
#[inline]
pub unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), 128);
    debug_assert_eq!(b.len(), 128);

    let mut sum = _mm512_setzero_ps();

    // Process 16 floats at a time (512 bits / 32 bits per float)
    for i in 0..8 {
        let offset = i * 16;
        let va = _mm512_loadu_ps(a.as_ptr().add(offset));
        let vb = _mm512_loadu_ps(b.as_ptr().add(offset));
        let diff = _mm512_sub_ps(va, vb);
        sum = _mm512_fmadd_ps(diff, diff, sum);
    }

    // Horizontal sum
    let sum_val = _mm512_reduce_add_ps(sum);
    (sum_val as f64).sqrt()
}

#[inline]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    #[cfg(target_arch = "x86_64")]
    {
        if is_x86_feature_detected!("avx512f") && a.len() == 128 {
            unsafe { l2_distance_avx512(a, b) }
        } else {
            l2_distance_fallback(a, b)
        }
    }
    #[cfg(not(target_arch = "x86_64"))]
    {
        l2_distance_fallback(a, b)
    }
}

#[inline]
fn l2_distance_fallback(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = 0.0f32;
    for i in 0..a.len() {
        let diff = a[i] - b[i];
        sum += diff * diff;
    }
    sum.sqrt() as f64
}
"}

