use crate::distance::l2_distance;
use std::sync::RwLock;
use rayon::prelude::*;

pub struct VectorDB {
    // Store vectors in a flat Vec for better cache locality
    // Each entry is (id, vector)
    data: RwLock<Vec<(u64, Vec<f32>)>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut data = self.data.write().unwrap();
        data.push((id, vector));
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut data = self.data.write().unwrap();
        let count = vectors.len();
        data.extend(vectors);
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let data = self.data.read().unwrap();

        // Parallel brute force search using rayon
        let mut results: Vec<SearchResult> = data
            .par_iter()
            .map(|(id, v)| SearchResult {
                id: *id,
                distance: l2_distance(vector, v),
            })
            .collect();

        // Partial sort to get top-k (faster than full sort)
        let k = (top_k as usize).min(results.len());
        results.select_nth_unstable_by(k, |a, b| a.distance.partial_cmp(&b.distance).unwrap());
        results.truncate(k);
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());

        results
    }
}
"}

